/// <summary>
///
/// </summary>
public void dialog()
{
    Dialog                       dialog;
    RefRecId                     recId;
    DialogField                  dialogArAPRef;
    ;

    dialog = new dialog("AED A/T Currency amount update");
    dialog.run();

    if (dialog.run())
    {
        this.create();
    }

}

/// <summary>
///
/// </summary>
/// <param name = "_fromdate"></param>
/// <param name = "_todate"></param>
public void create()
{
    ETGVoucherRecIdTable voucherTable;
    GeneralJournalAccountEntry gjAE;

    while select RecId, VoucherRecId from voucherTable 
    {
        ttsBegin;

        while select forUpdate gjAE
            where gjAE.GeneralJournalEntry == voucherTable.VoucherRecId
            && gjAE.TransactionCurrencyCode == 'AED'

        if (gjAE)
        {

            gjAE.AccountingCurrencyAmount = gjAE.AccountingCurrencyAmount / 1000;
            gjAE.TransactionCurrencyAmount = gjAE.TransactionCurrencyAmount / 1000;
            gjAE.update(); 
        }

        ttsCommit;
    }

    info("Update is completed.");

}

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGExchRateVouchersUpdate exchRateVouchersUpdate;

    exchRateVouchersUpdate = new ETGExchRateVouchersUpdate();
    exchRateVouchersUpdate.run();
}
